function p(e,r="YYYY-MM-DD HH:mm:ss"){if(!e)return"-";let t;if(typeof e=="string")t=new Date(e.replace(/-/g,"/"));else if(e instanceof Date)t=e;else return"-";if(isNaN(t.getTime()))return"-";const a=t.getFullYear(),n=String(t.getMonth()+1).padStart(2,"0"),s=String(t.getDate()).padStart(2,"0"),c=String(t.getHours()).padStart(2,"0"),o=String(t.getMinutes()).padStart(2,"0"),g=String(t.getSeconds()).padStart(2,"0");return r.replace("YYYY",a).replace("MM",n).replace("DD",s).replace("HH",c).replace("mm",o).replace("ss",g)}export{p as f};
